let currentAttempt = null;
let currentQuiz = null;
let currentQuestions = [];
let session = null;

async function loadExam() {
  session = getStoredSession();

  if (!session || !session.moodleQuizId) {
    showError('No quiz configured for this session');
    return;
  }

  try {
    setExamStatus('Connecting to Moodle...', 'info');

    // Fetch quiz details
    currentQuiz = await fetchMoodleQuiz(session.moodleQuizId, session.token);
    document.getElementById('quiz-title').textContent = currentQuiz.name;

    // Start attempt
    setExamStatus('Starting quiz...', 'info');
    currentAttempt = await startQuizAttempt(session.moodleQuizId, session.token);

    // Fetch questions
    setExamStatus('Loading questions...', 'info');
    currentQuestions = await fetchQuizQuestions(
      currentAttempt.id,
      session.moodleQuizId,
      session.token
    );

    // Render questions
    renderQuestions(currentQuestions);

    // Start timer
    startQuizTimer(currentQuiz.timelimit);

    // Enable submit button
    document.getElementById('submit-quiz').disabled = false;

    // Start proctoring
    startProctoring(session);

    setExamStatus('Quiz loaded successfully', 'success');

  } catch (error) {
    console.error('Failed to load quiz:', error);
    showError('Failed to load quiz: ' + error.message);
    markBackendDisconnected('Could not connect to Moodle');
  }
}

function renderQuestions(questions) {
  const container = document.getElementById('quiz-questions');
  container.innerHTML = '';

  questions.forEach((q, index) => {
    const questionDiv = document.createElement('div');
    questionDiv.className = 'question-item';
    questionDiv.dataset.slot = q.slot;

    const questionText = q.question.questiontext;

    questionDiv.innerHTML = `
      <h3>Question ${index + 1}</h3>
      <div class="question-text">${questionText}</div>
      <div class="question-input" data-slot="${q.slot}">
        <!-- TODO: Render appropriate input based on question type -->
        <textarea
          class="answer-textarea"
          data-slot="${q.slot}"
          placeholder="Enter your answer here..."
        ></textarea>
      </div>
    `;

    container.appendChild(questionDiv);
  });
}

async function submitQuiz() {
  if (!confirm('Are you sure you want to submit your quiz?')) {
    return;
  }

  try {
    setExamStatus('Submitting answers...', 'info');

    // Submit all answers
    const textareas = document.querySelectorAll('.answer-textarea');
    for (const textarea of textareas) {
      const slot = parseInt(textarea.dataset.slot, 10);
      const answer = { answer: textarea.value };

      await submitAnswer(currentAttempt.id, slot, answer, session.token);
    }

    // Finish attempt
    await finishQuiz(currentAttempt.id, session.token);

    setExamStatus('Quiz submitted successfully!', 'success');

    // Stop proctoring
    stopProctoring();

    // Show completion message
    showCompletionScreen();

  } catch (error) {
    console.error('Failed to submit quiz:', error);
    showError('Failed to submit quiz: ' + error.message);
  }
}

