  const response = await fetch(`${API_BASE_URL}/api/quiz/${quizId}`, {
    headers: {
      'Authorization': `Bearer ${token}`
    }
  });

  if (!response.ok) {
    throw new Error('Failed to fetch quiz');
  }

  const data = await response.json();
  return data.data;
}

/**
 * Start quiz attempt
 */
