const API_BASE_URL = 'http://localhost:5000';

/**
 * Fetch Moodle Quiz by ID
 */
async function fetchMoodleQuiz(quizId, token) {
  const response = await fetch(`${API_BASE_URL}/api/quiz/${quizId}`, {
    headers: {
      'Authorization': `Bearer ${token}`
    }
  });

  if (!response.ok) {
    throw new Error('Failed to fetch quiz');
  }

  const data = await response.json();
  return data.data;
}

/**
 * Start quiz attempt
 */
async function startQuizAttempt(quizId, token) {
  const response = await fetch(`${API_BASE_URL}/api/quiz/${quizId}/start`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`
    }
  });

  if (!response.ok) {
    throw new Error('Failed to start quiz');
  }

  const data = await response.json();
  return data.data;
}

/**
 * Fetch quiz questions
 */
async function fetchQuizQuestions(attemptId, quizId, token) {
  const response = await fetch(
    `${API_BASE_URL}/api/quiz/attempt/${attemptId}/questions?quizId=${quizId}`,
    {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    }
  );

  if (!response.ok) {
    throw new Error('Failed to fetch questions');
  }

  const data = await response.json();
  return data.data;
}

/**
 * Submit question answer
 */
async function submitAnswer(attemptId, slot, answer, token) {
  const response = await fetch(
    `${API_BASE_URL}/api/quiz/attempt/${attemptId}/submit`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ slot, response: answer })
    }
  );

  if (!response.ok) {
    throw new Error('Failed to submit answer');
  }

  return await response.json();
}

/**
 * Finish quiz attempt
 */
async function finishQuiz(attemptId, token) {
  const response = await fetch(
    `${API_BASE_URL}/api/quiz/attempt/${attemptId}/finish`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    }
  );

  if (!response.ok) {
    throw new Error('Failed to finish quiz');
  }

  return await response.json();
}
