export async function ltiRoutes(fastify: FastifyInstance) {
  // LTI launch endpoint (receives POST from Moodle)
  fastify.post('/lti/launch', {
    config: { public: true } // No auth required — LTI signature validates
  }, async (request, reply) => {
    try {
      const body = request.body as any;

      logger.info('LTI launch received', {
        context_id: body.context_id,
        context_label: body.context_label,
        resource_link_id: body.resource_link_id,
        user_id: body.user_id,
        roles: body.roles
      });

      // Validate OAuth 1.0 signature via ltijs
      const valid = await lti.validateLaunch(body);
      if (!valid) {
        return reply.code(403).send({
          success: false,
          error: 'Invalid LTI signature'
        });
      }

      // Extract LTI parameters
      const launchData = {
        contextId: body.context_id,
        contextLabel: body.context_label,
        contextTitle: body.context_title,
        resourceId: body.resource_link_id,
        resourceTitle: body.resource_link_title,
        userId: body.user_id,
