      if (isInstructor) {
        // Instructor → redirect to teacher dashboard or show room info
        return handleInstructorLaunch(launchData, reply);
      } else {
        // Student → join proctoring room
        return handleStudentLaunch(launchData, reply);
      }

    } catch (error) {
