### Phase 2: Moodle Quiz API Integration (Days 3-4)

**2.1 Extend moodle.service.ts for Quiz API**

Add to `backend/src/modules/auth/moodle.service.ts`:

```typescript
interface MoodleQuiz {
  id: number;
  course: number;
  coursename: string;
  name: string;
  intro: string;
  timeopen: number;
  timeclose: number;
  timelimit: number;
}

interface MoodleQuizQuestion {
  id: number;
  slot: number;
  type: string;
  question: {
    id: number;
    name: string;
    questiontext: string;
    defaultmark: number;
  };
}

interface MoodleQuizAttempt {
  id: number;
  quiz: number;
  attempt: number;
  state: 'inprogress' | 'finished' | 'abandoned';
  timestart: number;
  timefinish: number;
  timemodified: number;
}

/**
 * Get quiz by ID
 */
async getQuizById(token: string, quizId: number): Promise<MoodleQuiz> {
  const params = new URLSearchParams({
    wstoken: token,
    wsfunction: 'mod_quiz_get_quizzes_by_ids',
    moodlewsrestformat: 'json',
    'quizids[0]': quizId.toString()
  });

  const response = await axios.get(
    `${this.baseUrl}/webservice/rest/server.php`,
    { params }
  );

  if (response.data.quizzes && response.data.quizzes.length > 0) {
    return response.data.quizzes[0];
  }

  throw new MoodleError('Quiz not found');
}

/**
 * Get quiz questions for an attempt
 */
async getQuizQuestions(
  token: string,
  quizId: number,
  attemptId: number
): Promise<MoodleQuizQuestion[]> {
  const params = new URLSearchParams({
    wstoken: token,
    wsfunction: 'mod_quiz_get_attempt_data',
    moodlewsrestformat: 'json',
    attemptid: attemptId.toString(),
    page: '0'
  });

  const response = await axios.get(
    `${this.baseUrl}/webservice/rest/server.php`,
    { params }
  );

  return response.data.questions || [];
}

/**
 * Start new quiz attempt
 */
async startQuizAttempt(
  token: string,
  quizId: number,
  userid: number
): Promise<MoodleQuizAttempt> {
  const params = new URLSearchParams({
    wstoken: token,
    wsfunction: 'mod_quiz_start_attempt',
    moodlewsrestformat: 'json',
    quizid: quizId.toString(),
    userid: userid.toString(),
    prefetch: '1' // Preload questions
  });

  const response = await axios.post(
    `${this.baseUrl}/webservice/rest/server.php`,
    params
  );

  return response.data.attempt || response.data;
}

/**
 * Submit question response
 */
async submitQuestionResponse(
  token: string,
  attemptId: number,
  slot: number,
  response: Record<string, any>
): Promise<void> {
  const params = new URLSearchParams({
    wstoken: token,
    wsfunction: 'mod_quiz_process_attempt',
    moodlewsrestformat: 'json',
    attemptid: attemptId.toString(),
    data: JSON.stringify([{ slot, response }])
  });

  await axios.post(
    `${this.baseUrl}/webservice/rest/server.php`,
    params
  );
}

/**
 * Finish quiz attempt
 */
async finishQuizAttempt(token: string, attemptId: number): Promise<void> {
  const params = new URLSearchParams({
    wstoken: token,
    wsfunction: 'mod_quiz_process_attempt',
    moodlewsrestformat: 'json',
    attemptid: attemptId.toString(),
    finishattempt: '1'
  });

  await axios.post(
    `${this.baseUrl}/webservice/rest/server.php`,
    params
  );
}
