      // For production, implement IPC to main process for storage
      sandbox: false,
      webSecurity: true,
      allowRunningInsecureContent: false
    }
  });

  // Block navigation
  win.webContents.on('will-navigate', (event, url) => {
    event.preventDefault();
  });

  // Block new windows
  win.webContents.setWindowOpenHandler(() => {
    return { action: 'deny' };
  });

  // Disable dev tools in production
  if (process.env.NODE_ENV === 'production') {
    win.webContents.on('devtools-opened', () => {
      win.webContents.closeDevTools();
    });
  }

  // Prevent right-click
  win.webContents.on('context-menu', () => {
    // Don't show context menu
  });

  win.loadFile('renderer/exam.html');

  return win;
}
```

---

### Phase 4: Integration & Testing (Days 5-6)

**4.1 Update LTI launch to include quiz_id**

The LTI launch needs to know which Moodle Quiz to load. This is typically passed as a custom parameter in the External Tool configuration.

In Moodle, when configuring the External Tool:
- Tool URL: `http://localhost:5000/lti/launch`
- Consumer Key: `moodle`
- Secret: `changeme-secret-key`
- Privacy: Share launcher's name, email, role
- Custom parameters: `quiz_id=$resource.id` or specific quiz ID

Update `backend/src/modules/lti/lti.routes.ts`:

```typescript
async function handleStudentLaunch(launchData: any, reply: FastifyReply) {
  // Extract quiz_id from custom parameter
  const quizId = launchData.custom_quiz_id || launchData.resource_link_id;

  const roomCode = await getOrCreateRoomForContext(launchData, quizId);

  const token = jwt.sign({
    userId: launchData.userId,
    contextId: launchData.contextId,
    resourceId: launchData.resourceId,
    moodleQuizId: quizId, // Pass quiz ID to desktop app
    role: 'student',
    ltiLaunch: true,
    outcomeServiceUrl: launchData.outcomeServiceUrl,
    outcomeResultId: launchData.outcomeResultId
  }, process.env.JWT_SECRET || 'dev-secret', { expiresIn: '4h' });

  // Return HTML page that auto-launches desktop app
  return reply.type('text/html').send(`
    <!DOCTYPE html>
    <html>
    <head>
      <title>Launching Proctoring App...</title>
      <style>
        body { font-family: Arial, sans-serif; text-align: center; padding: 50px; }
        .spinner { border: 4px solid #f3f3f3; border-top: 4px solid #3498db;
                  border-radius: 50%; width: 40px; height: 40px;
                  animation: spin 1s linear infinite; margin: 20px auto; }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
      </style>
    </head>
    <body>
      <h2>Launching Proctoring Desktop App...</h2>
      <div class="spinner"></div>
      <p>If the app doesn't open automatically, <a href="proctor://launch?room=${roomCode}&token=${token}">click here</a>.</p>
      <script>
        // Auto-launch after 2 seconds
        setTimeout(() => {
          window.location = 'proctor://launch?room=${roomCode}&token=${token}';
        }, 2000);
      </script>
    </body>
    </html>
  `);
}
```

**4.2 Register custom URL protocol in Electron**

In `manual_proctoring/main.js`:

```javascript
const { app, protocol } = require('electron');

// Register custom protocol
app.setAsDefaultProtocolClient('proctor');

// Handle protocol launch
app.on('open-url', (event, url) => {
  event.preventDefault();
  handleProctorUrl(url);
});

function handleProctorUrl(url) {
  const urlParams = new URL(url);
  const room = urlParams.searchParams.get('room');
  const token = urlParams.searchParams.get('token');

  // Store token and room
  localStorage.setItem('authSession', JSON.stringify({ room, token }));
  localStorage.setItem('token', token);

  // Open exam window
  createExamWindow();
}
```

**4.3 End-to-end integration tests**

