**2.2 Create Quiz proxy endpoint**

Create `backend/src/modules/quiz/quiz.routes.ts`:

```typescript
import { FastifyInstance } from 'fastify';
import moodleService from '../auth/moodle.service';
import { authMiddleware } from '../../middleware/auth.middleware';

export async function quizRoutes(fastify: FastifyInstance) {
  // Get quiz details
  fastify.get('/api/quiz/:quizId', {
    preHandler: [authMiddleware]
  }, async (request, reply) => {
    const { quizId } = request.params as { quizId: string };
    const user = (request as any).user;

    try {
      const quiz = await moodleService.getQuizById(
        user.moodleToken,
        parseInt(quizId, 10)
      );

      return {
        success: true,
        data: quiz
      };
    } catch (error) {
      logger.error('Failed to fetch quiz:', error);
      return reply.code(500).send({
        success: false,
        error: 'Failed to load quiz'
      });
    }
  });

  // Start quiz attempt
  fastify.post('/api/quiz/:quizId/start', {
    preHandler: [authMiddleware]
  }, async (request, reply) => {
    const { quizId } = request.params as { quizId: string };
    const user = (request as any).user;

    try {
      const attempt = await moodleService.startQuizAttempt(
        user.moodleToken,
        parseInt(quizId, 10),
        user.moodleUserId
      );

      return {
        success: true,
        data: attempt
      };
    } catch (error) {
      logger.error('Failed to start quiz:', error);
      return reply.code(500).send({
        success: false,
        error: 'Failed to start quiz'
      });
    }
  });

  // Get quiz questions
  fastify.get('/api/quiz/attempt/:attemptId/questions', {
    preHandler: [authMiddleware]
  }, async (request, reply) => {
    const { attemptId } = request.params as { attemptId: string };
    const { quizId } = request.query as { quizId: string };
    const user = (request as any).user;

    try {
      const questions = await moodleService.getQuizQuestions(
        user.moodleToken,
        parseInt(quizId, 10),
        parseInt(attemptId, 10)
      );

      return {
        success: true,
        data: questions
      };
    } catch (error) {
      logger.error('Failed to fetch questions:', error);
      return reply.code(500).send({
        success: false,
        error: 'Failed to load questions'
      });
    }
  });

  // Submit answer
  fastify.post('/api/quiz/attempt/:attemptId/submit', {
    preHandler: [authMiddleware]
  }, async (request, reply) => {
    const { attemptId } = request.params as { attemptId: string };
    const { slot, response } = request.body as { slot: number; response: any };
    const user = (request as any).user;

    try {
      await moodleService.submitQuestionResponse(
        user.moodleToken,
        parseInt(attemptId, 10),
        slot,
        response
      );

      return { success: true };
    } catch (error) {
      logger.error('Failed to submit answer:', error);
      return reply.code(500).send({
        success: false,
        error: 'Failed to submit answer'
      });
    }
  });

  // Finish quiz
  fastify.post('/api/quiz/attempt/:attemptId/finish', {
    preHandler: [authMiddleware]
  }, async (request, reply) => {
    const { attemptId } = request.params as { attemptId: string };
    const user = (request as any).user;

    try {
      await moodleService.finishQuizAttempt(
        user.moodleToken,
        parseInt(attemptId, 10)
      );

      return { success: true };
    } catch (error) {
      logger.error('Failed to finish quiz:', error);
      return reply.code(500).send({
        success: false,
        error: 'Failed to finish quiz'
      });
    }
  });
}
```

