function createExamWindow() {
  const win = new BrowserWindow({
    width: 1400,
    height: 900,
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
      // CRITICAL: sandbox: false to allow localStorage in renderer
      // Sandboxed renderers cannot access localStorage or sessionStorage
      // For production, implement IPC to main process for storage
      sandbox: false,
      webSecurity: true,
      allowRunningInsecureContent: false
    }
  });

  // Block navigation
  win.webContents.on('will-navigate', (event, url) => {
    event.preventDefault();
  });

  // Block new windows
  win.webContents.setWindowOpenHandler(() => {
    return { action: 'deny' };
  });

  // Disable dev tools in production
  if (process.env.NODE_ENV === 'production') {
    win.webContents.on('devtools-opened', () => {
      win.webContents.closeDevTools();
    });
  }

  // Prevent right-click
  win.webContents.on('context-menu', () => {
    // Don't show context menu
  });

  win.loadFile('renderer/exam.html');

  return win;
}
