export async function sendScoreToMoodle(
  outcomeServiceUrl: string,
  outcomeResultId: string,
  consumerSecret: string,
  score: OutcomeScore
): Promise<boolean> {
  // Build POX (XML over HTTP) request body
  const poxXml = `
    <?xml version="1.0" encoding="UTF-8"?>
    <imsx_POXEnvelopeRequest xmlns="http://www.imsglobal.org/services/ltiv1p1/xsd/imsoms_v1p0">
      <imsx_POXHeader>
        <imsx_POXRequestHeaderInfo>
          <imsx_version>V1.0</imsx_version>
          <imsx_messageIdentifier>${generateMessageId()}</imsx_messageIdentifier>
        </imsx_POXRequestHeaderInfo>
      </imsx_POXHeader>
      <imsx_POXBody>
        <replaceResultRequest>
          <resultRecord>
            <sourcedGUID>
              <sourcedId>${outcomeResultId}</sourcedId>
            </sourcedGUID>
            <result>
              <resultScore>
                <language>en</language>
                <textString>${score.score.toString()}</textString>
              </resultScore>
              <resultTotalScore>
                <language>en</language>
                <textString>${score.maximum.toString()}</textString>
              </resultTotalScore>
            </result>
          </resultRecord>
        </replaceResultRequest>
      </imsx_POXBody>
    </imsx_POXEnvelopeRequest>
  `;

  try {
    const response = await axios.post(outcomeServiceUrl, poxXml, {
      headers: {
        'Content-Type': 'application/xml'
      }
    });

    // Check for success response
    if (response.data.includes('success')) {
      return true;
    }

    console.error('LTI Outcome failed:', response.data);
    return false;

  } catch (error) {
    console.error('LTI Outcome error:', error);
    return false;
  }
}

function generateMessageId(): string {
  return Date.now().toString() + Math.random().toString(36).substring(7);
}
```

**5.2 Call grade passback after quiz submission**

Update quiz finish endpoint in `backend/src/modules/quiz/quiz.routes.ts`:

```typescript
// Finish quiz
fastify.post('/api/quiz/attempt/:attemptId/finish', {
  preHandler: [authMiddleware]
}, async (request, reply) => {
  const { attemptId } = request.params as { attemptId: string };
  const user = (request as any).user;

  try {
    await moodleService.finishQuizAttempt(
      user.moodleToken,
      parseInt(attemptId, 10)
    );

    // Send grade passback via LTI if available
    if (user.outcomeServiceUrl && user.outcomeResultId) {
      const score = {
        score: 1.0, // Pass (assuming submission = pass)
        maximum: 1.0,
        minimum: 0.0
      };

      const sent = await sendScoreToMoodle(
        user.outcomeServiceUrl,
        user.outcomeResultId,
        process.env.LTI_CONSUMER_SECRET || 'secret',
        score
      );

      if (sent) {
        logger.info('Grade sent to Moodle via LTI');
      } else {
        logger.warn('Failed to send grade to Moodle');
      }
    }

    return { success: true };
  } catch (error) {
    logger.error('Failed to finish quiz:', error);
    return reply.code(500).send({
      success: false,
      error: 'Failed to finish quiz'
    });
  }
});
```

