              border-radius: 6px;
              font-weight: 600;
              transition: background 0.2s;
              margin-top: 10px;
            }
            a:hover { background: #5568d3; }
            .fallback {
              margin-top: 30px;
              padding-top: 20px;
              border-top: 1px solid #e0e0e0;
            }
            .error {
              background: #fee;
              color: #c33;
              padding: 12px;
              border-radius: 6px;
              margin: 20px 0;
            }
          </style>
        </head>
        <body>
          <div class="container">
