    21→
    22→// Import routes
    23→import authRoutes from './modules/auth/auth.routes';
    24→import studentRoutes from './modules/student/student.routes';
    25→import examRoutes from './modules/exam/exam.routes';
    26→import violationRoutes from './modules/violation/violation.routes';
