    30→import roomRoutes from './modules/room/room.routes';
    31→
    32→// ============================================================================
    33→// Feature Flags
    34→// ============================================================================
    35→
    36→export const featureFlags = {
    37→  webrtcEnabled: false,
    38→};
    39→
    40→// ============================================================================
    41→// Create Fastify App
    42→// ============================================================================
    43→
    44→export async function createApp() {
    45→  const app = Fastify({
    46→    logger: false, // We use Winston instead
    47→    disableRequestLogging: true,
    48→    trustProxy: true,
    49→  });
    50→
    51→  // ==========================================================================
    52→  // Register Global Plugins
    53→  // ==========================================================================
    54→
    55→  // CORS
    56→  const allowedOrigins = config.cors.origin
    57→    .split(',')
    58→    .map(origin => origin.trim())
    59→    .filter(Boolean);
    60→
    61→  await app.register(cors, {
    62→    origin: (origin, callback) => {
    63→      // Allow Electron/file-based clients and non-browser tools without Origin headers.
    64→      if (!origin) {
    65→        callback(null, true);
    66→        return;
    67→      }
    68→
    69→      callback(null, allowedOrigins.includes(origin));
    70→    },
    71→    credentials: config.cors.credentials,
    72→  });
    73→
    74→  // JWT
    75→  await app.register(jwt, {
    76→    secret: config.jwt.secret,
    77→  });
    78→
    79→  // Cookie support
