// ============================================================================
// LTI Protocol Handler (proctor://)
// Allows deep linking from Moodle LTI launch
// ============================================================================

const PROTOCOL_SCHEME = 'proctor'

// Set default protocol client (registers proctor:// scheme)
// For development, this may fail if already registered by another instance
const locked = app.requestSingleInstanceLock()

if (!locked) {
  // Another instance is already running - pass args to it and quit
  console.log('Another instance is already running - passing protocol arguments')
  app.quit()
} else {
  // This is the primary instance - handle protocol launches from other instances
  app.on('second-instance', (event, commandLine, workingDirectory) => {
    console.log('Second instance detected - checking for protocol arguments')
    console.log('Command line args:', commandLine)

    // Check if any command line argument is a proctor:// URL
    const protocolArg = commandLine.find(arg => arg.startsWith(`${PROTOCOL_SCHEME}://`))

    if (protocolArg) {
      console.log('Protocol argument found:', protocolArg)

      // Bring main window to front
      if (mainWindow) {
        if (mainWindow.isMinimized()) mainWindow.restore()
        mainWindow.focus()

        // Send protocol URL to renderer process
        handleProtocolUrl(protocolArg)
      }
    }
  })
}

// macOS: Handle protocol URLs when app is already running
app.on('open-url', (event, url) => {
  event.preventDefault()
  console.log('open-url event received:', url)

  if (url.startsWith(`${PROTOCOL_SCHEME}://`)) {
    // Bring main window to front
    if (mainWindow) {
      if (mainWindow.isMinimized()) mainWindow.restore()
      mainWindow.focus()

      // Send protocol URL to renderer process
      handleProtocolUrl(url)
    }
  }
})

// Parse protocol URL and extract parameters
function handleProtocolUrl (url) {
  console.log('Handling protocol URL:', url)

  try {
    const parsedUrl = new URL(url)
    const roomCode = parsedUrl.searchParams.get('room')
    const token = parsedUrl.searchParams.get('token')

    console.log('Parsed protocol URL:', {
      roomCode,
      hasToken: !!token
    })

    // Send to renderer process for auto-login
    if (mainWindow && !mainWindow.isDestroyed()) {
      mainWindow.webContents.send('lti-launch', {
        roomCode,
        token
      })
    }
  } catch (error) {
    console.error('Failed to parse protocol URL:', error)
  }
}

// Register protocol handler (must be before app.whenReady())
if (app.isPackaged) {
  // Production: Register protocol handler
  app.setAsDefaultProtocolClient(PROTOCOL_SCHEME)
} else {
  // Development: Set protocol handler (may fail if already registered)
  try {
    app.setAsDefaultProtocolClient(PROTOCOL_SCHEME)
  } catch (error) {
    console.warn('Failed to set protocol handler in development (may already be registered):', error.message)
  }
}

app.whenReady().then(createWindow)

