function handleLtiLaunch(data) {
  console.log('LTI launch received:', data)

  const { roomCode, token } = data

  if (!token) {
    console.error('LTI launch missing token')
    setMessage('LTI launch failed: missing authentication token', 'error')
    return
  }

  // Store the LTI token in localStorage
  storeSession({
    token: token,
    expiresAt: Date.now() + (24 * 60 * 60 * 1000), // 24 hours
    student: null, // No student info yet
    ltiLaunch: true, // Flag as LTI launch
    roomCode: roomCode
  })

  // Redirect to join page with room code
  if (roomCode) {
    console.log('Redirecting to join page with room code:', roomCode)
    window.location.href = `join.html?room=${encodeURIComponent(roomCode)}&lti=1`
  } else {
    console.log('Redirecting to dashboard (no room code)')
    window.location.href = 'dashboard.html'
  }
}

// Listen for LTI launch events from main process
if (window.electronAPI && window.electronAPI.onLtiLaunch) {
  window.electronAPI.onLtiLaunch((data) => {
    console.log('LTI launch event received:', data)
    handleLtiLaunch(data)
  })
} else {
  console.warn('electronAPI.onLtiLaunch not available')
}

